import AppKit

/// flow's brand mark — the "w" wave from assets/flow-logo.svg in the public
/// repo (gradient #0AEAA8 → #0ADCCE → #198FFF). Embedded as base64 so it works
/// in the hand-assembled .app bundle without a resource copy step. Rendered at
/// @2x (height 36px); displayed ~16pt tall in the menubar, non-template so the
/// gradient shows.
enum BrandIcon {
    static let menubar: NSImage = {
        let data = Data(base64Encoded: base64PNG) ?? Data()
        let image = NSImage(data: data) ?? NSImage(
            systemSymbolName: "point.3.connected.trianglepath.dotted",
            accessibilityDescription: "Flow")!
        // Menubar icons read best ~13-14pt tall; the "w" is ~2:1 so we size
        // by height and let width follow, keeping it compact next to system
        // icons.
        let targetHeight = 11.0
        image.size = NSSize(
            width: targetHeight * (image.size.width / max(image.size.height, 1)),
            height: targetHeight)
        image.isTemplate = false
        return image
    }()

    private static let base64PNG = ""
}
